import 'dart:io'; import 'dart:convert'; void main() async { var urls = ['https://play.google.com/store/apps/details?id=com.bubbles.blooddonation', 'https://play.google.com/store/apps/details?id=com.paaldappa.user', 'https://play.google.com/store/apps/details?id=com.srihari.vidyapathi']; for (var u in urls) { var r = await HttpClient().getUrl(Uri.parse(u)); var res = await r.close(); var body = await res.transform(Utf8Decoder()).join(); var match = RegExp(r'<meta property=\"og:image\" content=\"([^\"]+)\"').firstMatch(body); print(match?.group(1)); } }
